 1	import React, { FC } from 'react';
 2	import { TooltipRenderProps } from 'react-joyride';
 3	
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { Button, ButtonVariant, Split, SplitItem } from '@patternfly/react-core';
 6	import { CloseIcon } from '@patternfly/react-icons';
 7	import { css } from '@patternfly/react-styles';
 8	import popoverStyles from '@patternfly/react-styles/css/components/Popover/popover';
 9	
10	import EndTourFooter from '../EndTourFooter/EndTourFooter';
11	
12	import './TourPopover.scss';
13	
14	const TourPopover: FC<TooltipRenderProps> = ({
15	  backProps,
16	  closeProps,
17	  index,
18	  isLastStep,
19	  primaryProps,
20	  size,
21	  step,
22	}) => {
23	  const { t } = useKubevirtTranslation();
24	  return (
25	    <div className={css(popoverStyles.popover, 'kv-tour-popover')}>
26	      <Split>
27	        {step.title && <SplitItem className="kv-tour-popover__header">{step.title}</SplitItem>}
28	        <SplitItem isFilled />
29	        <SplitItem>
30	          <Button
31	            {...closeProps}
32	            className="pf-v6-c-popover__close"
33	            icon={<CloseIcon />}
34	            variant={ButtonVariant.plain}
35	          />
36	        </SplitItem>
37	      </Split>
38	      <div className={css(popoverStyles.popoverContent)}>{step.content}</div>
39	      <Split className="kv-tour-popover__buttons-footer" hasGutter>
40	        <SplitItem className="kv-tour-popover__step-counter">
41	          {t('Step {{current}}/{{size}}', { current: index + 1, size })}
42	        </SplitItem>
43	        <SplitItem isFilled />
44	        {index > 0 && (
45	          <SplitItem>
46	            <Button
47	              {...backProps}
48	              className="kv-tour-popover__next"
49	              variant={ButtonVariant.secondary}
50	            >
51	              {t('Back')}
52	            </Button>
53	          </SplitItem>
54	        )}
55	        <SplitItem>
56	          <Button
57	            {...primaryProps}
58	            className="kv-tour-popover__previous"
59	            variant={ButtonVariant.primary}
60	          >
61	            {isLastStep ? t('Okay, got it!') : t('Next')}
62	          </Button>
63	        </SplitItem>
64	      </Split>
65	      {isLastStep && <EndTourFooter />}
66	    </div>
67	  );
68	};
69	
70	export default TourPopover;

